let taskSet = new Set();
function ensureVideoIsMP4(inputPath) {
    // 定义输出路径，通过替换 /dtimg/ 为 /dtimgs/ 来构造
    const outputPath = inputPath.replace('/original/', '/compressed/');
    // 检查转换后的文件是否已经存在
    if (fs_1.default.existsSync(outputPath)) {
        if (videoSet.has(inputPath)) {
            return inputPath;
        }
        console.log(`转换后的文件已经存在: ${outputPath}`);
        return outputPath;
    }
    if (taskSet.has(outputPath)) {
        return inputPath;
    }
    taskSet.add(outputPath);
    console.log(`正在转换视频: ${inputPath} -> ${outputPath}`);
    if (videoSet.size >= 1) {
        return inputPath;
    }
    if (fs_1.default.statSync(inputPath).size >= 10 * 1024 * 1024 * 1024) {
        return inputPath;
    }
    videoSet.add(inputPath);
    // 用 ffprobe 检查视频编码
    const codecInfo = (0, child_process_1.execSync)(`ffprobe -v error -select_streams v:0 -show_entries stream=codec_name -of csv=p=0 ${inputPath}`).toString().trim();
    const audioInfo = (0, child_process_1.execSync)(`ffprobe -v error -select_streams a:0 -show_entries stream=codec_name -of csv=p=0 ${inputPath}`).toString().trim();
    let args;
    if (codecInfo === 'h264' && audioInfo === 'aac') {
        // 已经是 h264 + aac，直接 copy
        args = ['-i', inputPath, '-c:v', 'copy', '-c:a', 'copy', '-y', outputPath];
    }
    else {
        // 否则强制转码
        args = ['-i', inputPath, '-c:v', 'libx264', '-c:a', 'aac', '-y', outputPath];
    }
    const ffmpeg = (0, child_process_1.spawn)('ffmpeg', args);
    // 捕获 ffmpeg 的标准错误输出
    ffmpeg.stderr.on('data', (data) => {
        console.error('FFmpeg输出:', data.toString());
    });
    // ffmpeg 处理完成后的回调
    ffmpeg.on('close', (code) => {
        if (code === 0) {
            console.log(`视频转换成功: ${outputPath}`);
        }
        else {
            // (new Error(`FFmpeg 进程退出，状态码: ${code}`)); // 转换失败
            console.log('转换失败');
        }
        videoSet.delete(inputPath);
    });
    // 错误处理
    ffmpeg.on('error', (err) => {
        console.log("错误");
        videoSet.delete(inputPath);
    });
    return inputPath;
}
