function calculateDirectionAndDistance(lon1, lat1, lon2, lat2) {
    // 常量
    const R = 6371; // 地球半径（千米）
    // 将经纬度转换为弧度
    const lat1Rad = lat1 * (Math.PI / 180);
    const lon1Rad = lon1 * (Math.PI / 180);
    const lat2Rad = lat2 * (Math.PI / 180);
    const lon2Rad = lon2 * (Math.PI / 180);
    // Haversine 公式计算距离
    const dLat = lat2Rad - lat1Rad;
    const dLon = lon2Rad - lon1Rad;
    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
        Math.cos(lat1Rad) * Math.cos(lat2Rad) *
            Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    const distance = R * c; // 距离（千米）
    // 计算方向
    const y = Math.sin(dLon) * Math.cos(lat2Rad);
    const x = Math.cos(lat1Rad) * Math.sin(lat2Rad) -
        Math.sin(lat1Rad) * Math.cos(lat2Rad) * Math.cos(dLon);
    let bearing = Math.atan2(y, x) * (180 / Math.PI); // 方向（度）
    // 将方向调整到0到360度之间
    bearing = (bearing + 360) % 360;
    return { distance, bearing };
}
function lvi(req, res) {
    const src = req.query.src;
    if (!src) {
        return res.send({ code: 400 });
    }
    const videoPath = (0, pathUtils_1.getUrl)('assets', 'longVideo', src.toString()); // 获取视频文件的路径
    const stat = fs_1.default.statSync(videoPath); // 获取文件状态
    const fileSize = stat.size; // 文件大小
    const range = req.headers.range; // 获取请求头中的 Range 信息
    if (range) {
        const parts = range.replace(/bytes=/, '').split('-'); // 解析 Range
        const start = parseInt(parts[0], 10); // 起始字节
        const end = parts[1] ? parseInt(parts[1], 10) : fileSize - 1; // 结束字节
        if (start >= fileSize || end >= fileSize || start > end) {
            res.status(416).send('Requested Range Not Satisfiable'); // 请求的范围不满足
            return;
        }
        const chunkSize = end - start + 1; // 计算分片大小
        const fileStream = fs_1.default.createReadStream(videoPath, { start, end }); // 创建文件流
        res.writeHead(206, {
            'Content-Range': `bytes ${start}-${end}/${fileSize}`,
            'Accept-Ranges': 'bytes',
            'Content-Length': chunkSize,
            'Content-Type': 'video/mp4', // 设置内容类型
        });
        fileStream.pipe(res); // 将文件流返回给客户端
    }
    else {
        // 如果没有 Range 头，返回整个文件
        res.writeHead(200, {
            'Content-Length': fileSize,
            'Content-Type': 'video/mp4',
        });
        fs_1.default.createReadStream(videoPath).pipe(res); // 返回整个视频
    }
}
